"""
GUAVA EXAMPLE
Type: Outbound
Scenario: Restaurant Waitlist
"""

import guava
import logging
import os
import argparse

from typing_extensions import override
from guava.helpers.openai import IntentRecognizer
from guava import logging_utils

logger = logging.getLogger("guava.examples.thai_palace")


class ThaiPalaceCallController(guava.CallController):
    def __init__(self):
        super().__init__()
        self.intent_recognizer = IntentRecognizer(['restaurant waitlist', 'anything else'])
        self.set_persona(
            organization_name="Thai Palace"
        )


    @override
    def on_incoming_call(self, from_number: str | None):
        self.set_thai_palace_task()
        self.accept_call()

    def set_thai_palace_task(self):
        self.set_task(
            objective="""You are a virtual assistant for a restaurant called Thai Palace.
Your job is to add callers to the waitlist.""",
            checklist=[
                guava.Field(
                    key="caller_name",
                    field_type="text",
                    description="The name to be added to the waitlist"),
                guava.Field(
                    key="party_size",
                    field_type="integer",
                    description="The number of people attending"),
                guava.Field(
                    key="phone_number",
                    field_type="text",
                    description="phone number to text when table is ready"),
                "Read the phone number back to the caller to make sure you got it right"
            ],
            on_complete=self.hangup
        )

    @override
    def on_intent(self, intent: str):
        choice = self.intent_recognizer.classify(intent)
        logger.info("Chosen intent: %s", choice)
        if choice == "restaurant waitlist":
            self.set_thai_palace_task()
        else:
            return "Tell them we only handle waitlist additions at this number."
        
    @override
    def on_session_done(self):
        caller_name = self.get_field('caller_name')
        party_size = self.get_field('party_size')
        logger.info(f"Reservation for {caller_name}, party of {party_size}.")


if __name__ == "__main__":
    logging_utils.configure_logging()
    
    parser = argparse.ArgumentParser()
    args = parser.parse_args()

    guava.Client().listen_inbound(
        agent_number=os.environ['GUAVA_AGENT_NUMBER'],
        controller_class=ThaiPalaceCallController,
    )